_POOLS = {"lot": CHINESE_LOTS, "tarot": TAROT_READINGS}
_BAGS = {"lot": [], "tarot": []}


def draw_fortune(mode, rng=None):
    rng = rng or random
    key = mode if mode in _POOLS else "lot"
    pool = _POOLS[key]
    bag = _BAGS[key]
    if not bag:
        bag.extend(range(len(pool)))
        rng.shuffle(bag)
    idx = bag.pop()
    result = dict(pool[idx])
    result["mode"] = key
    result["mode_label"] = MODE_LABELS[key]
    return result
